          <section>
            <CreatePost onSubmit={handleCreatePost} />
          </section>

          <section className="space-y-4">
            {posts.map((post) => (
              <GratitudeCard 
                key={post.id} 
                post={post}
              />
            ))}
          </section>

          <div className="text-center py-8 text-sm text-zinc-600">
            <p>Breathe in. Breathe out.</p>
          </div>
        </div>
      </div>
    </div>
  );
}

