import { Link, useLocation } from "wouter";
import { Plus, Users, User, Home } from "lucide-react";
import { cn } from "@/lib/utils";

export function Layout({ children }: { children: React.ReactNode }) {
  const [location] = useLocation();

  const navItems = [
    { href: "/check-in", icon: Home, label: "Home" },
    { href: "/friends", icon: Users, label: "Friends" },
    { href: "/me", icon: User, label: "Me" },
  ];

  return (
    <div className="min-h-screen bg-club-blue text-white font-sans pb-24">
      {children}

      <nav className="fixed bottom-0 left-0 right-0 z-50 bg-white text-club-blue shadow-[0_-4px_20px_rgba(0,0,0,0.1)] pb-safe">
        <div className="mx-auto flex max-w-md items-center justify-around px-4 py-3">
          {navItems.map((item) => {
            const isActive = location === item.href;
            return (
              <Link key={item.href} href={item.href}>
                <div className={cn(
                  "flex flex-col items-center gap-1 transition-all cursor-pointer group w-16",
                  isActive ? "text-club-blue" : "text-gray-400 hover:text-club-blue/70"
                )}>
                  <div className={cn(
                    "rounded-full p-1.5 transition-all transform duration-200",
                    isActive ? "bg-blue-50 scale-110" : ""
